@@ -848,6 +848,24 @@ Instruction *InstCombinerImpl::visitTrunc(TruncInst &Trunc) {
         // trunc (C << X) to i1 --> X == 0, where C is odd
         return new ICmpInst(ICmpInst::Predicate::ICMP_EQ, X, Zero);
       }
+      
+      const APInt *C2;
+      if (match(Src, m_Shr(m_Power2(C2), m_Value(X)))) {
+        // trunc (C >> X) to i1 --> X == cttz(C), where C is pow2
+        Constant *Log2C = ConstantInt::get(SrcTy, C2->exactLogBase2());
+        return new ICmpInst(ICmpInst::Predicate::ICMP_EQ, X, Log2C);
+      }
+      if (match(Src, m_Shr(m_Add(m_Power2(C2), m_AllOnes()), m_Value(X)))) {
+        // trunc ((C - 1) >> X) to i1 --> X < cttz(C), where C is pow2
+        Constant *Log2C = ConstantInt::get(SrcTy, C2->exactLogBase2());
+        return new ICmpInst(ICmpInst::Predicate::ICMP_ULT, X, Log2C);
+      }
+      
+      const APInt *C3;
+      if (match(Src, m_Shr(m_APInt(C3), m_Value(X))) && (*C3 + 1).isPowerOf2()) {
+        Constant *Log2C = ConstantInt::get(SrcTy, (*C3 + 1).exactLogBase2());
+        return new ICmpInst(ICmpInst::Predicate::ICMP_ULT, X, Log2C);
+      }
     }

